const (
	ERR_INVALID_PARAM               int32 = 1 // Invalid parameters
	ERR_SWITCH_PREVENTED            int32 = 2 // Switching failed due to an alarm that may be overridden
	ERR_SWITCH_FAILED               int32 = 3 // Switching failed, no override possible
	OPERATIONAL_STATE_OFF           int32 = 0 // Both inlets are off
	OPERATIONAL_STATE_NORMAL        int32 = 1 // Active inlet equals preferred inlet
	OPERATIONAL_STATE_STANDBY       int32 = 2 // Active inlet and preferred inlet are different
	OPERATIONAL_STATE_NON_REDUNDANT int32 = 3 // Active inlet equals preferred inlet, standby power critical
	OPERATIONAL_STATE_BYPASSED      int32 = 4 // Both inlets are off, but bypass is active
	SWITCH_FAULT_I1_SHORT           int32 = 1 // Inlet 1 switch is permanently closed
	SWITCH_FAULT_I1_OPEN            int32 = 2 // Inlet 1 switch is permanently open
	SWITCH_FAULT_I2_SHORT           int32 = 4 // Inlet 2 switch is permanently closed
	SWITCH_FAULT_I2_OPEN            int32 = 8 // Inlet 2 switch is permanently open
)

// Transfer switch interface
type TransferSwitch interface {
	edevice.EDevice

	// Retrieve the transfer switch metadata.
	//
	//	@return Transfer switch metadata
	GetMetaData(ctx context.Context) (MetaData, error)

	// Get the transfer switch sensors.
	//
	//	@return Transfer switch sensors
	GetSensors(ctx context.Context) (Sensors, error)

	// Get the list of transfer switch poles.
	//
	//	@return List of poles
	GetPoles(ctx context.Context) ([]pole.ThrowPole, error)

	// Retrieve the transfer switch settings.
	//
	//	@return Transfer switch settings
	GetSettings(ctx context.Context) (Settings, error)

	// Change the transfer switch settings.
	//
	//	@return 0 if OK
	//	@return 1 if any parameters are invalid
	//
	//	@note The Settings structure can be "sparse"; fields missing in the
	//	      JSON representation will remain unchanged.
	SetSettings(ctx context.Context, settings Settings) (int32, error)

	// Retrieve the transfer switch statistics.
	//
	//	@return Transfer switch statistics
	GetStatistics(ctx context.Context) (Statistics, error)

	// Select the active inlet. If the new inlet is available,
	// it will become both active and preferred.
	//
	//	@param source         New active inlet index
	//	@param faultOverride  Force switch even if the phase sync angle
	//	                      between the inputs is too large
	//
	//	@return 0 if OK
	//	@return ERR_INVALID_PARAM if the selected source is invalid
	//	@return ERR_SWITCH_PREVENTED if switching failed due to an alarm that may be overridden
	//	@return ERR_SWITCH_FAILED if switching failed and no override is possible
	TransferToSource(ctx context.Context, source int32, faultOverride bool) (int32, error)

	// Get the reason for the last transfer.
	//
	//	@return Last transfer reason
	GetLastTransferReason(ctx context.Context) (TransferReason, error)

	// Get the voltage and current waveforms during the last transfer.
	//
	//	@return Waveform samples
	GetLastTransferWaveform(ctx context.Context) (waveform.Waveform, error)

	// Retrieve the transfer log.
	//
	//	@return Transfer log
	GetTransferLog(ctx context.Context) ([]TransferLogEntry, error)

	// Retrieve the transfer switch parameters.
	//
	//	@return Parameters map
	GetParameters(ctx context.Context) (Parameters, error)

	// Update one or more transfer switch parameters.
	//
	//	@param parameters  Map of transfer switch parameters. Parameters
	//	                   which are not in the map remain unchanged.
	//
	//	@return 0 if OK
	//	@return ERR_INVALID_PARAM if any parameter is invalid
	SetParameters(ctx context.Context, parameters Parameters) (int32, error)
}

// Transfer switch type
type Type int

const (
	STS Type = iota // Static transfer switch (using SCRs as switch technology)
	ATS             // Asynchronous transfer switch (using relays)
	HTS             // Hybrid transfer switch (relays plus SCRs)
)

type TransferReason int

const (
	REASON_UNKNOWN          TransferReason = iota // Transfer reason unknown
	REASON_STARTUP                                // Startup or return to normal conditions
	REASON_MANUAL_TRANSFER                        // Manual transfer
	REASON_AUTO_RETRANSFER                        // Automatic retransfer
	REASON_POWER_FAILURE                          // Previous inlet power failed
	REASON_POWER_QUALITY                          // New inlet provided better power quality
	REASON_OVERLOAD                               // Switched off due to overload alarm
	REASON_OVERHEAT                               // Switched off due to overheat alarm
	REASON_INTERNAL_FAILURE                       // Transferred because of hardware failure (e.g. switch fault)
	REASON_BYPASS_ACTIVE                          // Switched off due to active bypass
)

// Transfer switch metadata
type MetaData struct {
	Label       string              // Transfer switch label
	NamePlate   nameplate.Nameplate // Nameplate information
	Rating      nameplate.Rating    // Numerical usage ratings
	Type        Type                // Transfer switch type
	SourceCount int32               // Number of sources
}

// Transfer switch sensors
type Sensors struct {
	SelectedSource              statesensor.StateSensor     // Selected source sensor
	OperationalState            statesensor.StateSensor     // Operational state sensor (off, normal, standby)
	SourceVoltagePhaseSyncAngle numericsensor.NumericSensor // Maximum phase difference between two sources
	OverloadAlarm               statesensor.StateSensor     // Overload alarm
	PhaseSyncAlarm              statesensor.StateSensor     // Source phases out of sync
	SwitchFault                 statesensor.StateSensor     // Switch fault (ok, open, short)
	InstallFaultAlarm           statesensor.StateSensor     // Install fault alarm
	OutputStatus                statesensor.StateSensor     // Output voltage status (ok, fault)
	BypassState                 transferswitchbypassstatesensor.TransferSwitchBypassStateSensor
}

// Transfer switch settings
type Settings struct {
	Name                         string // User-defined name
	PreferredSource              int32  // Preferred inlet
	AutoRetransfer               bool   // Enable automatic retransfer if power on active inlet is restored
	NoAutoRetransferIfPhaseFault bool   // Don't automatically retransfer if inlet phases are out of sync
	AutoRetransferWaitTime       int32  // Time (in s) to delay retransfer after power restoration
	ManualTransferEnabled        bool   // Enable state of 'manual transfer' front panel button
	PhaseSyncSensorEnabled       bool   // False to force the 'phaseSyncAlarm' sensor to unavailable
}

// Transfer switch statistics
type Statistics struct {
	TransferCount          int32 // Number of transfers since device startup
	PowerFailDetectTime    int32 // Detection time in us for the last inlet power failure
	RelayOpenTime          int32 // Time in us until all relays have opened during the last transfer
	TotalTransferTime      int32 // Total time in us for last transfer
	OverloadCount          int32 // Number of outlet overloads since device startup
	SwitchOvercurrentCount int32 // Number of internal over current occurrences during switching since device startup
}

// Event: Transfer switch settings have been changed
type SettingsChangedEvent interface {
	userevent.UserEvent
	OldSettings() Settings // Settings before change
	NewSettings() Settings // Settings after change
	isSettingsChangedEvent()
}

// Transfer log entry
type TransferLogEntry struct {
	Timestamp   time.Time         // Time of the transfer (UNIX timestamp, UTC)
	OldInlet    int32             // Active inlet before transfer (0 for none)
	NewInlet    int32             // Active inlet after transfer (0 for none)
	Reason      TransferReason    // Transfer reason
	Waveform    waveform.Waveform // Voltage and current waveforms
	Statistics  Statistics        // Transfer statistics
	SwitchFault int32             // Switch fault status
}

// Transfer switch parameter map.
//
// The set of parameters, their meaning and allowed set of values are
// technology-dependent and subject to change. Do not modify any values
// without instruction from Raritan!
type Parameters = map[string]int32
